/*
 * COMP 421 Lab 3: Yalnix File System Server
 *
 * Main YFS server process that handles file system operations via IPC.
 */

#include <comp421/yalnix.h>
#include <comp421/hardware.h>
#include <comp421/filesystem.h>
#include <string.h>
#include <stdio.h>

/* Forward declarations */
int ReadSector(int sector, char *buffer);
int WriteSector(int sector, char *buffer);

/* Global file system state */
static char disk_buffer[BLOCKSIZE];
static struct fs_header *fs_header;
static int num_inodes, num_blocks;

/* ========================================================================
 * Initialization
 * ======================================================================== */

int
InitFileSystem()
{
    /* Read super block from disk */
    if (ReadSector(1, disk_buffer) < 0) {
        TracePrintf(1, "Failed to read super block\n");
        return -1;
    }

    /* Parse file system header */
    fs_header = (struct fs_header *)disk_buffer;
    num_blocks = fs_header->num_blocks;
    num_inodes = fs_header->num_inodes;

    TracePrintf(1, "YFS: Initialized with %d blocks, %d inodes\n",
                num_blocks, num_inodes);

    return 0;
}

/* ========================================================================
 * Message Handling
 * ======================================================================== */

void
HandleMessage(struct msg_header *msg, int src_pid)
{
    /* TODO: Implement message dispatch based on message type */
    TracePrintf(1, "YFS: Received message from PID %d\n", src_pid);
}

/* ========================================================================
 * Main YFS Server Loop
 * ======================================================================== */

int
main()
{
    int status;
    struct msg_header msg;
    int pid;

    TracePrintf(1, "YFS: Starting file system server\n");

    /* Initialize file system */
    if (InitFileSystem() < 0) {
        TracePrintf(1, "YFS: Failed to initialize file system\n");
        Exit(-1);
    }

    /* Register as FILE_SERVER */
    status = Register(FILE_SERVER);
    if (status < 0) {
        TracePrintf(1, "YFS: Failed to register as FILE_SERVER\n");
        Exit(-1);
    }

    TracePrintf(1, "YFS: Registered as FILE_SERVER\n");

    /* Main message loop */
    while (1) {
        /* Wait for incoming message */
        pid = Receive(&msg, sizeof(msg));
        if (pid < 0) {
            TracePrintf(1, "YFS: Receive error: %d\n", pid);
            continue;
        }

        /* Handle the message */
        HandleMessage(&msg, pid);

        /* Send reply */
        Send(pid, &msg, sizeof(msg));
    }

    return 0;
}

/*
 * COMP 421 Lab 3: Yalnix File System Client Library
 *
 * User-level procedures for file system operations via IPC.
 */

#include <comp421/yalnix.h>
#include <comp421/filesystem.h>
#include <comp421/iolib.h>
#include <string.h>

/* ========================================================================
 * Client-side File Descriptor Table
 * ======================================================================== */

#define MAX_FD 16

struct file_desc {
    int inum;           /* Inode number */
    int offset;         /* Current file position */
    int reuse;          /* Reuse count from server */
    int in_use;         /* Whether this FD is open */
};

static struct file_desc fd_table[MAX_FD];
static int current_dir_inum = ROOTINODE;
static int next_fd = 0;

/* ========================================================================
 * Client-side Message Structure (32 bytes fixed)
 * ======================================================================== */

struct yfs_msg {
    int op;             /* Operation type */
    int fd;             /* File descriptor */
    int inum;           /* Inode number */
    int offset;         /* Offset or seek position */
    int size;           /* Size or return value */
    int whence;         /* Seek mode */
    int path_len;       /* Pathname length */
    int inum2;          /* Second inode number (for link ops) */
};

#define OP_OPEN    1
#define OP_CLOSE   2
#define OP_CREATE  3
#define OP_READ    4
#define OP_WRITE   5
#define OP_SEEK    6
#define OP_MKDIR   7
#define OP_RMDIR   8
#define OP_UNLINK  9
#define OP_LINK    10
#define OP_STAT    11
#define OP_CHDIR   12
#define OP_SYNC    13
#define OP_SHUTDOWN 14

/* ========================================================================
 * Helper Functions
 * ======================================================================== */

static int
GetNextFD()
{
    int i;
    for (i = 0; i < MAX_FD; i++) {
        if (!fd_table[i].in_use) {
            fd_table[i].in_use = 1;
            return i;
        }
    }
    return -1;
}

static int
SendRequest(struct yfs_msg *msg, const char *pathname)
{
    int pid;

    /* Get FILE_SERVER PID */
    pid = Lookup(FILE_SERVER);
    if (pid < 0) {
        return -1;
    }

    /* Send message */
    if (pathname && msg->path_len > 0) {
        CopyTo(pid, pathname, (void *)(long)next_fd, msg->path_len);
    }

    Send(pid, msg, sizeof(*msg));

    /* Receive reply */
    Receive(msg, sizeof(*msg));

    return msg->size;
}

/* ========================================================================
 * Library Functions
 * ======================================================================== */

int
Open(const char *pathname)
{
    struct yfs_msg msg;
    int fd, result;

    if (!pathname) {
        return -1;
    }

    /* Get next available FD */
    fd = GetNextFD();
    if (fd < 0) {
        return -1;
    }

    /* Prepare message */
    memset(&msg, 0, sizeof(msg));
    msg.op = OP_OPEN;
    msg.path_len = strlen(pathname) + 1;

    /* Send request to server */
    result = SendRequest(&msg, pathname);
    if (result < 0) {
        fd_table[fd].in_use = 0;
        return -1;
    }

    /* Store FD info */
    fd_table[fd].inum = msg.inum;
    fd_table[fd].offset = 0;
    fd_table[fd].reuse = msg.whence;

    return fd;
}

int
Close(int fd)
{
    struct yfs_msg msg;

    if (fd < 0 || fd >= MAX_FD || !fd_table[fd].in_use) {
        return -1;
    }

    /* Prepare message */
    memset(&msg, 0, sizeof(msg));
    msg.op = OP_CLOSE;
    msg.fd = fd;
    msg.inum = fd_table[fd].inum;
    msg.offset = fd_table[fd].offset;

    /* Send to server */
    int pid = Lookup(FILE_SERVER);
    if (pid < 0) {
        return -1;
    }
    Send(pid, &msg, sizeof(msg));
    Receive(&msg, sizeof(msg));

    /* Clear FD */
    fd_table[fd].in_use = 0;

    return msg.size;
}

int
Create(const char *pathname)
{
    struct yfs_msg msg;
    int fd, result;

    if (!pathname) {
        return -1;
    }

    /* Get next available FD */
    fd = GetNextFD();
    if (fd < 0) {
        return -1;
    }

    /* Prepare message */
    memset(&msg, 0, sizeof(msg));
    msg.op = OP_CREATE;
    msg.path_len = strlen(pathname) + 1;

    /* Send request to server */
    result = SendRequest(&msg, pathname);
    if (result < 0) {
        fd_table[fd].in_use = 0;
        return -1;
    }

    /* Store FD info */
    fd_table[fd].inum = msg.inum;
    fd_table[fd].offset = 0;
    fd_table[fd].reuse = msg.whence;

    return fd;
}

int
Read(int fd, void *buf, int nbytes)
{
    struct yfs_msg msg;
    int pid, nread;

    if (fd < 0 || fd >= MAX_FD || !fd_table[fd].in_use || !buf) {
        return -1;
    }

    /* Prepare message */
    memset(&msg, 0, sizeof(msg));
    msg.op = OP_READ;
    msg.fd = fd;
    msg.inum = fd_table[fd].inum;
    msg.offset = fd_table[fd].offset;
    msg.size = nbytes;

    /* Send to server */
    pid = Lookup(FILE_SERVER);
    if (pid < 0) {
        return -1;
    }
    Send(pid, &msg, sizeof(msg));

    /* Receive message */
    Receive(&msg, sizeof(msg));
    nread = msg.size;

    if (nread > 0) {
        /* Copy data from server */
        CopyFrom(pid, (void *)(long)fd, buf, nread);
        fd_table[fd].offset += nread;
    }

    return nread;
}

int
Write(int fd, const void *buf, int nbytes)
{
    struct yfs_msg msg;
    int pid, nwritten;

    if (fd < 0 || fd >= MAX_FD || !fd_table[fd].in_use || !buf) {
        return -1;
    }

    /* Prepare message */
    memset(&msg, 0, sizeof(msg));
    msg.op = OP_WRITE;
    msg.fd = fd;
    msg.inum = fd_table[fd].inum;
    msg.offset = fd_table[fd].offset;
    msg.size = nbytes;

    /* Send to server */
    pid = Lookup(FILE_SERVER);
    if (pid < 0) {
        return -1;
    }

    /* Copy data to server */
    CopyTo(pid, buf, (void *)(long)fd, nbytes);

    Send(pid, &msg, sizeof(msg));

    /* Receive reply */
    Receive(&msg, sizeof(msg));
    nwritten = msg.size;

    if (nwritten > 0) {
        fd_table[fd].offset += nwritten;
    }

    return nwritten;
}

int
Seek(int fd, int offset, int whence)
{
    struct yfs_msg msg;
    int pid, new_offset;

    if (fd < 0 || fd >= MAX_FD || !fd_table[fd].in_use) {
        return -1;
    }

    /* Prepare message */
    memset(&msg, 0, sizeof(msg));
    msg.op = OP_SEEK;
    msg.fd = fd;
    msg.inum = fd_table[fd].inum;
    msg.offset = offset;
    msg.whence = whence;
    msg.size = fd_table[fd].offset;

    /* Send to server */
    pid = Lookup(FILE_SERVER);
    if (pid < 0) {
        return -1;
    }
    Send(pid, &msg, sizeof(msg));
    Receive(&msg, sizeof(msg));

    new_offset = msg.size;
    if (new_offset >= 0) {
        fd_table[fd].offset = new_offset;
    }

    return new_offset;
}

int
MkDir(const char *pathname)
{
    struct yfs_msg msg;

    if (!pathname) {
        return -1;
    }

    /* Prepare message */
    memset(&msg, 0, sizeof(msg));
    msg.op = OP_MKDIR;
    msg.path_len = strlen(pathname) + 1;

    /* Send request to server */
    return SendRequest(&msg, pathname);
}

int
RmDir(const char *pathname)
{
    struct yfs_msg msg;

    if (!pathname) {
        return -1;
    }

    /* Prepare message */
    memset(&msg, 0, sizeof(msg));
    msg.op = OP_RMDIR;
    msg.path_len = strlen(pathname) + 1;

    /* Send request to server */
    return SendRequest(&msg, pathname);
}

int
Unlink(const char *pathname)
{
    struct yfs_msg msg;

    if (!pathname) {
        return -1;
    }

    /* Prepare message */
    memset(&msg, 0, sizeof(msg));
    msg.op = OP_UNLINK;
    msg.path_len = strlen(pathname) + 1;

    /* Send request to server */
    return SendRequest(&msg, pathname);
}

int
Link(const char *oldpath, const char *newpath)
{
    /* TODO: Implement Link operation */
    return -1;
}

int
ChDir(const char *pathname)
{
    struct yfs_msg msg;
    int pid, result;

    if (!pathname) {
        return -1;
    }

    /* Prepare message */
    memset(&msg, 0, sizeof(msg));
    msg.op = OP_CHDIR;
    msg.path_len = strlen(pathname) + 1;

    /* Send request to server */
    result = SendRequest(&msg, pathname);
    if (result >= 0) {
        current_dir_inum = msg.inum;
    }

    return result;
}

int
Stat(const char *pathname, struct stat *statbuf)
{
    /* TODO: Implement Stat operation */
    return -1;
}

int
Sync()
{
    struct yfs_msg msg;
    int pid;

    /* Prepare message */
    memset(&msg, 0, sizeof(msg));
    msg.op = OP_SYNC;

    /* Send to server */
    pid = Lookup(FILE_SERVER);
    if (pid < 0) {
        return -1;
    }
    Send(pid, &msg, sizeof(msg));
    Receive(&msg, sizeof(msg));

    return msg.size;
}

int
Shutdown()
{
    struct yfs_msg msg;
    int pid;

    /* Prepare message */
    memset(&msg, 0, sizeof(msg));
    msg.op = OP_SHUTDOWN;

    /* Send to server */
    pid = Lookup(FILE_SERVER);
    if (pid < 0) {
        return -1;
    }
    Send(pid, &msg, sizeof(msg));
    Receive(&msg, sizeof(msg));

    return msg.size;
}

