/*
 * COMP 421 Lab 3: Yalnix File System Client Library
 *
 * User-level procedures for file system operations via IPC.
 */

#include <comp421/yalnix.h>
#include <comp421/filesystem.h>
#include <comp421/iolib.h>
#include <string.h>

/* ========================================================================
 * Client-side File Descriptor Table
 * ======================================================================== */

#define MAX_FD 16

struct file_desc {
    int inum;           /* Inode number */
    int offset;         /* Current file position */
    int reuse;          /* Reuse count from server */
    int in_use;         /* Whether this FD is open */
};

static struct file_desc fd_table[MAX_FD];
static int current_dir_inum = ROOTINODE;

/* ========================================================================
 * Client-side Message Structure (32 bytes fixed)
 * ======================================================================== */

struct yfs_msg {
    int op;             /* Operation type */
    int fd;             /* File descriptor */
    int inum;           /* Inode number */
    int offset;         /* Offset or seek position */
    int size;           /* Size or return value */
    int whence;         /* Seek mode */
    int path_len;       /* Pathname length */
    int inum2;          /* Second inode number (for link ops) */
};

#define OP_OPEN    1
#define OP_CLOSE   2
#define OP_CREATE  3
#define OP_READ    4
#define OP_WRITE   5
#define OP_SEEK    6
#define OP_MKDIR   7
#define OP_RMDIR   8
#define OP_UNLINK  9
#define OP_LINK    10
#define OP_STAT    11
#define OP_CHDIR   12
#define OP_SYNC    13
#define OP_SHUTDOWN 14

/* ========================================================================
 * Helper Functions
 * ======================================================================== */

static int
GetNextFD()
{
    int i;
    for (i = 0; i < MAX_FD; i++) {
        if (!fd_table[i].in_use) {
            fd_table[i].in_use = 1;
            return i;
        }
    }
    return -1;
}

static int
SendRequest(struct yfs_msg *msg, const char *pathname)
{
    int pid;

    /* Get FILE_SERVER PID */
    pid = Lookup(FILE_SERVER);
    if (pid < 0) {
        return -1;
    }

    /* Send message */
    Send((void *)msg, pid);

    /* Receive reply */
    Receive((void *)msg);

    return msg->size;
}

/* ========================================================================
 * Library Functions
 * ======================================================================== */

int
Open(char *pathname)
{
    struct yfs_msg msg;
    int fd, result;

    if (!pathname) {
        return -1;
    }

    /* Get next available FD */
    fd = GetNextFD();
    if (fd < 0) {
        return -1;
    }

    /* Prepare message */
    memset(&msg, 0, sizeof(msg));
    msg.op = OP_OPEN;
    msg.path_len = strlen(pathname) + 1;

    /* Send request to server */
    result = SendRequest(&msg, pathname);
    if (result < 0) {
        fd_table[fd].in_use = 0;
        return -1;
    }

    /* Store FD info */
    fd_table[fd].inum = msg.inum;
    fd_table[fd].offset = 0;
    fd_table[fd].reuse = msg.whence;

    return fd;
}

int
Close(int fd)
{
    struct yfs_msg msg;
    int pid;

    if (fd < 0 || fd >= MAX_FD || !fd_table[fd].in_use) {
        return -1;
    }

    /* Prepare message */
    memset(&msg, 0, sizeof(msg));
    msg.op = OP_CLOSE;
    msg.fd = fd;
    msg.inum = fd_table[fd].inum;
    msg.offset = fd_table[fd].offset;

    /* Send to server */
    pid = Lookup(FILE_SERVER);
    if (pid < 0) {
        return -1;
    }
    Send((void *)&msg, pid);
    Receive((void *)&msg);

    /* Clear FD */
    fd_table[fd].in_use = 0;

    return msg.size;
}

int
Create(char *pathname)
{
    struct yfs_msg msg;
    int fd, result;

    if (!pathname) {
        return -1;
    }

    /* Get next available FD */
    fd = GetNextFD();
    if (fd < 0) {
        return -1;
    }

    /* Prepare message */
    memset(&msg, 0, sizeof(msg));
    msg.op = OP_CREATE;
    msg.path_len = strlen(pathname) + 1;

    /* Send request to server */
    result = SendRequest(&msg, pathname);
    if (result < 0) {
        fd_table[fd].in_use = 0;
        return -1;
    }

    /* Store FD info */
    fd_table[fd].inum = msg.inum;
    fd_table[fd].offset = 0;
    fd_table[fd].reuse = msg.whence;

    return fd;
}

int
Read(int fd, void *buf, int nbytes)
{
    struct yfs_msg msg;
    int pid, nread;

    if (fd < 0 || fd >= MAX_FD || !fd_table[fd].in_use || !buf) {
        return -1;
    }

    /* Prepare message */
    memset(&msg, 0, sizeof(msg));
    msg.op = OP_READ;
    msg.fd = fd;
    msg.inum = fd_table[fd].inum;
    msg.offset = fd_table[fd].offset;
    msg.size = nbytes;

    /* Send to server */
    pid = Lookup(FILE_SERVER);
    if (pid < 0) {
        return -1;
    }
    Send((void *)&msg, pid);

    /* Receive message */
    Receive((void *)&msg);
    nread = msg.size;

    if (nread > 0) {
        /* Copy data from server */
        CopyFrom(pid, (void *)(long)fd, buf, nread);
        fd_table[fd].offset += nread;
    }

    return nread;
}

int
Write(int fd, void *buf, int nbytes)
{
    struct yfs_msg msg;
    int pid, nwritten;

    if (fd < 0 || fd >= MAX_FD || !fd_table[fd].in_use || !buf) {
        return -1;
    }

    /* Prepare message */
    memset(&msg, 0, sizeof(msg));
    msg.op = OP_WRITE;
    msg.fd = fd;
    msg.inum = fd_table[fd].inum;
    msg.offset = fd_table[fd].offset;
    msg.size = nbytes;

    /* Send to server */
    pid = Lookup(FILE_SERVER);
    if (pid < 0) {
        return -1;
    }

    /* Copy data to server */
    CopyTo(pid, buf, (void *)(long)fd, nbytes);

    Send((void *)&msg, pid);

    /* Receive reply */
    Receive((void *)&msg);
    nwritten = msg.size;

    if (nwritten > 0) {
