{
    struct yfs_msg msg;
    int pid, new_offset;

    if (fd < 0 || fd >= MAX_FD || !fd_table[fd].in_use) {
        return -1;
    }

    /* Prepare message */
    memset(&msg, 0, sizeof(msg));
    msg.op = OP_SEEK;
    msg.fd = fd;
    msg.inum = fd_table[fd].inum;
    msg.offset = offset;
    msg.whence = whence;
    msg.size = fd_table[fd].offset;

    /* Send to server */
    pid = Lookup(FILE_SERVER);
    if (pid < 0) {
        return -1;
    }
    Send((void *)&msg, pid);
    Receive((void *)&msg);

