static int
GetNextFD()
{
    int i;
    for (i = 0; i < MAX_FD; i++) {
        if (!fd_table[i].in_use) {
            fd_table[i].in_use = 1;
            return i;
        }
    }
    return -1;
}

static int
SendRequest(struct yfs_msg *msg)
{
    /* Send message to FILE_SERVER */
    Send((void *)msg, -FILE_SERVER);

    /* Receive reply */
    Receive((void *)msg);

    return msg->size;
}

