int
Open(char *pathname)
{
    struct yfs_msg msg;
    int fd, result;

    if (!pathname) {
        return -1;
    }

    /* Get next available FD */
    fd = GetNextFD();
    if (fd < 0) {
        return -1;
    }

    /* Prepare message */
    memset(&msg, 0, sizeof(msg));
    msg.op = OP_OPEN;
    msg.path_len = strlen(pathname) + 1;

    /* Send request to server */
    result = SendRequest(&msg);
    if (result < 0) {
        fd_table[fd].in_use = 0;
        return -1;
    }

    /* Store FD info */
    fd_table[fd].inum = msg.inum;
    fd_table[fd].offset = 0;
    fd_table[fd].reuse = msg.whence;

    return fd;
}

int
Close(int fd)
{
    struct yfs_msg msg;

    if (fd < 0 || fd >= MAX_FD || !fd_table[fd].in_use) {
        return -1;
    }

    /* Prepare message */
    memset(&msg, 0, sizeof(msg));
    msg.op = OP_CLOSE;
    msg.fd = fd;
    msg.inum = fd_table[fd].inum;
    msg.offset = fd_table[fd].offset;

    /* Send to server */
    Send((void *)&msg, -FILE_SERVER);
    Receive((void *)&msg);

    /* Clear FD */
    fd_table[fd].in_use = 0;

    return msg.size;
}

