    msg.op = OP_READ;
    msg.fd = fd;
    msg.inum = fd_table[fd].inum;
    msg.offset = fd_table[fd].offset;
    msg.size = nbytes;

    /* Send to server */
    Send((void *)&msg, -FILE_SERVER);

