/* ========================================================================
 * Client-side File Descriptor Table
 * ======================================================================== */

#define MAX_FD 16

struct file_desc {
    int inum;           /* Inode number */
    int offset;         /* Current file position */
    int reuse;          /* Reuse count from server */
    int in_use;         /* Whether this FD is open */
};

static struct file_desc fd_table[MAX_FD];
static int current_dir_inum = ROOTINODE;

/* Shared buffer for pathname transfers */
static char pathname_buffer[MAXPATHNAMELEN];
static char read_buffer[8192];  /* Buffer for Read data transfer */

/* ========================================================================
 * Client-side Message Structure (32 bytes fixed)
 * ======================================================================== */

struct yfs_msg {
    int op;             /* Operation type */
    int fd;             /* File descriptor */
    int inum;           /* Inode number */
    int offset;         /* Offset or seek position */
    int size;           /* Size or return value */
    int whence;         /* Seek mode / reuse count / result */
    long path_ptr;      /* Pointer to pathname in client space */
    int path_len;       /* Pathname length */
};

#define OP_OPEN    1
#define OP_CLOSE   2
#define OP_CREATE  3
#define OP_READ    4
#define OP_WRITE   5
#define OP_SEEK    6
#define OP_MKDIR   7
#define OP_RMDIR   8
#define OP_UNLINK  9
#define OP_LINK    10
#define OP_STAT    11
#define OP_CHDIR   12
#define OP_SYNC    13
#define OP_SHUTDOWN 14

/* ========================================================================
 * Helper Functions
 * ======================================================================== */

static int
GetNextFD()
{
    int i;
    for (i = 0; i < MAX_FD; i++) {
        if (!fd_table[i].in_use) {
            fd_table[i].in_use = 1;
            return i;
        }
    }
    return -1;
}

static int
SendRequest(struct yfs_msg *msg, const char *pathname)
{
    int len = 0;

    /* Copy pathname to shared buffer if provided */
    if (pathname) {
        len = strlen(pathname) + 1;
        if (len > MAXPATHNAMELEN) {
            return -1;
        }
        memcpy(pathname_buffer, pathname, len);
        msg->path_ptr = (long)pathname_buffer;
        msg->path_len = len;
    } else {
        msg->path_ptr = 0;
        msg->path_len = 0;
    }

    /* Send message to FILE_SERVER */
    Send((void *)msg, -FILE_SERVER);

    /* Receive reply */
    Receive((void *)msg);

    return msg->size;
}

