int
Read(int fd, void *buf, int nbytes)
{
    struct yfs_msg msg;
    int nread;
    int server_pid;

    if (fd < 0 || fd >= MAX_FD || !fd_table[fd].in_use || !buf) {
        return -1;
    }

    if (nbytes < 0) {
        return -1;
    }

    /* Prepare message */
    memset(&msg, 0, sizeof(msg));
    msg.op = OP_READ;
    msg.fd = fd;
    msg.inum = fd_table[fd].inum;
    msg.offset = fd_table[fd].offset;
    msg.size = nbytes;
    msg.path_ptr = (long)read_buffer;
    msg.path_len = sizeof(read_buffer);

    /* Send to server */
    server_pid = Lookup(FILE_SERVER);
    if (server_pid < 0) {
        server_pid = -FILE_SERVER;  /* Try using negative */
    }
    Send((void *)&msg, -FILE_SERVER);

    /* Receive message */
    Receive((void *)&msg);
    nread = msg.size;

    if (nread > 0 && nread <= nbytes) {
        /* Copy data from read_buffer to user buffer */
        memcpy(buf, read_buffer, nread);
        fd_table[fd].offset += nread;
    }

    return nread;
}

int
Write(int fd, void *buf, int nbytes)
{
    struct yfs_msg msg;
    int nwritten;

    if (fd < 0 || fd >= MAX_FD || !fd_table[fd].in_use || !buf) {
        return -1;
    }

    if (nbytes < 0) {
        return -1;
    }

    /* Copy data to shared buffer */
    if (nbytes > (int)sizeof(read_buffer)) {
        nbytes = sizeof(read_buffer);
    }
    memcpy(read_buffer, buf, nbytes);

    /* Prepare message */
    memset(&msg, 0, sizeof(msg));
    msg.op = OP_WRITE;
    msg.fd = fd;
    msg.inum = fd_table[fd].inum;
    msg.offset = fd_table[fd].offset;
    msg.size = nbytes;
    msg.path_ptr = (long)read_buffer;
    msg.path_len = nbytes;

    /* Send to server */
