        break;
    case OP_READ:
        HandleRead(msg, client_pid);
        break;
    case OP_WRITE:
        HandleWrite(msg, client_pid);
        break;
    case OP_CLOSE:
        HandleClose(msg, client_pid);
        break;
    case OP_SEEK:
        HandleSeek(msg, client_pid);
        break;
    case OP_MKDIR:
        HandleMkDir(msg, client_pid);
        break;
    case OP_RMDIR:
        HandleRmDir(msg, client_pid);
        break;
    case OP_UNLINK:
        HandleUnlink(msg, client_pid);
        break;
    case OP_STAT:
        HandleStat(msg, client_pid);
        break;
    case OP_SHUTDOWN:
        HandleShutdown(msg, client_pid);
        break;
    case OP_SYNC:
        HandleSync(msg, client_pid);
        break;
    default:
        TtyPrintf(1, "YFS: Unknown operation %d\n", msg->op);
        msg->size = -1;
        break;
    }
