/* ========================================================================
 * Main YFS Server Loop
 * ======================================================================== */

int
main()
{
    int status;
    struct yfs_msg msg;
    int pid;

    TtyPrintf(1, "YFS: Starting file system server\n");

    /* Initialize file system */
    if (InitFileSystem() < 0) {
        TtyPrintf(1, "YFS: Failed to initialize file system\n");
        Exit(-1);
    }

    /* Register as FILE_SERVER */
    status = Register(FILE_SERVER);
    if (status < 0) {
        TtyPrintf(1, "YFS: Failed to register as FILE_SERVER\n");
        Exit(-1);
    }

    TtyPrintf(1, "YFS: Registered as FILE_SERVER\n");

    /* Main message loop */
    while (1) {
        /* Wait for incoming message */
        pid = Receive((void *)&msg);
        if (pid < 0) {
            TtyPrintf(1, "YFS: Receive error: %d\n", pid);
            continue;
        }

        /* Handle the message */
        HandleMessage(&msg, pid);

        /* Send reply */
        Reply((void *)&msg, pid);
    }

    return 0;
}

