/*
 * COMP 421 Lab 3: File System Implementation Helpers
 *
 * This file contains the core file system operation implementations.
 * It's included in yfs.c after the basic infrastructure.
 */

/*
 * AddDirEntry: Add a directory entry to a directory inode
 * Returns 0 on success, -1 on failure
 */
int
AddDirEntry(int dir_inum, int target_inum, const char *name)
{
    struct inode *dir = GetInode(dir_inum);
    if (!dir || dir->type != INODE_DIRECTORY) {
        return -1;
    }

    int i, j, nentries, block_num;
    struct dir_entry *entry;
    char *block_data;

    /* Look for empty entry in existing blocks */
    for (i = 0; i < NUM_DIRECT && dir->direct[i] != 0; i++) {
        block_data = GetBlock(dir->direct[i]);
        if (!block_data) {
            continue;
        }

        nentries = BLOCKSIZE / sizeof(struct dir_entry);
        for (j = 0; j < nentries; j++) {
            entry = (struct dir_entry *)(block_data + j * sizeof(struct dir_entry));
            if (entry->inum == 0) {  /* Free entry */
                entry->inum = (short)target_inum;
                memcpy(entry->name, name, DIRNAMELEN);
                PutBlock(dir->direct[i]);
                return 0;
            }
        }
    }

    /* Need new block - allocate one */
    if (i >= NUM_DIRECT) {
        return -1;  /* No more direct blocks */
    }

    block_num = AllocateBlock();
    if (block_num < 0) {
        return -1;
    }

    dir->direct[i] = block_num;
    block_data = GetBlock(block_num);
    if (!block_data) {
        return -1;
    }

    /* Clear the block and add first entry */
    memset(block_data, 0, BLOCKSIZE);
    entry = (struct dir_entry *)block_data;
    entry->inum = (short)target_inum;
    memcpy(entry->name, name, DIRNAMELEN);
    dir->size += BLOCKSIZE;

    PutBlock(block_num);
    PutInode(dir_inum);
    return 0;
}

/*
 * GetLastComponent: Extract the last component of a pathname
 * Modifies pathname_buffer
 */
void
GetLastComponent(const char *pathname, char *last_component)
{
    int i, last_slash = -1;
    const char *p = pathname;

    /* Find last '/' */
    for (i = 0; p[i] != '\0'; i++) {
        if (p[i] == '/') {
            last_slash = i;
        }
    }

    /* Copy component after last slash */
    if (last_slash >= 0) {
        strcpy(last_component, p + last_slash + 1);
    } else {
        strcpy(last_component, p);
    }
}

/*
 * GetParentPath: Extract parent directory path from full pathname
 */
void
GetParentPath(const char *pathname, char *parent_path)
{
    int i, last_slash = -1;
    const char *p = pathname;

    /* Find last '/' */
    for (i = 0; p[i] != '\0'; i++) {
        if (p[i] == '/') {
            last_slash = i;
        }
    }

    if (last_slash <= 0) {
        /* No parent or root parent */
        strcpy(parent_path, "/");
    } else {
        /* Copy up to last slash */
        strncpy(parent_path, p, last_slash);
        parent_path[last_slash] = '\0';
    }
}

/*
 * FindOrCreateFile: Find or create a file with given pathname
 * Returns inode number on success, -1 on error
 */
int
FindOrCreateFile(const char *pathname, int create_mode, int *is_new)
{
    *is_new = 0;

    /* Try to find existing file */
    int inum = TraversePath(pathname);
    if (inum >= 0) {
        struct inode *file = GetInode(inum);
        if (create_mode && file && file->type == INODE_REGULAR) {
            /* Truncate existing file */
            file->size = 0;
            memset(file->direct, 0, sizeof(file->direct));
            file->indirect = 0;
            PutInode(inum);
            *is_new = 1;
            return inum;
        }
        return inum;
    }

    /* File doesn't exist - create it if requested */
    if (!create_mode) {
        return -1;
    }

    /* Allocate new inode */
    inum = AllocateInode(INODE_REGULAR);
    if (inum < 0) {
        return -1;
    }

    /* Get parent directory and add entry */
    char parent_path[MAXPATHNAMELEN];
    char last_comp[DIRNAMELEN + 1];

    GetParentPath(pathname, parent_path);
    GetLastComponent(pathname, last_comp);

    int parent_inum = TraversePath(parent_path);
    if (parent_inum < 0) {
        /* Parent doesn't exist either */
        return -1;
    }

    if (AddDirEntry(parent_inum, inum, last_comp) < 0) {
        return -1;
    }

    *is_new = 1;
    return inum;
}
